#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(char*)a - *(char*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[500001];
        scanf("%s", s);
        int count = 0;
        for (int i = 0; i <= strlen(s) - 4; i++) {
            char sub[5];
            strncpy(sub, s + i, 4);
            sub[4] = '\0';
            char chef[] = "chef";
            qsort(sub, 4, sizeof(char), compare);
            qsort(chef, 4, sizeof(char), compare);
            if (strcmp(sub, chef) == 0) {
                count++;
            }
        }
        if (count == 0) {
            printf("normal\n");
        } else {
            printf("lovely %d\n", count);
        }
    }
    return 0;
}

