using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        string s;
        cin >> s;
        int count = 0;
        for (int i = 0; i <= s.length() - 4; i++) {
            string sub = s.substr(i, 4);
            string chef = "chef";
            sort(sub.begin(), sub.end());
            sort(chef.begin(), chef.end());
            if (sub == chef) {
                count++;
            }
        }
        if (count == 0) {
            cout << "normal" << endl;
        } else {
            cout << "lovely " << count << endl;
        }
    }
    return 0;
}

code.Java:
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String s = sc.nextLine();
            int count = 0;
            for (int i = 0; i <= s.length() - 4; i++) {
                String sub = s.substring(i, i + 4);
                char[] subArray = sub.toCharArray();
                char[] chefArray = "chef".toCharArray();
                Arrays.sort(subArray);
                Arrays.sort(chefArray);
                if (new String(subArray).equals(new String(chefArray))) {
                    count++;
                }
            }
            if (count == 0) {
                System.out.println("normal");
            } else {
                System.out.println("lovely " + count);
            }
        }
    }
}

